var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"레드시프트 습격 <color=#ffd34c>이틀 뒤</color>","JPN":"レッドシフトの襲撃から<color=#ffd34c>二日後</color>","ENG":"<color=#ffd34c>Two days after</color> the Red Shift ambush","TWN":"紅移突襲 <color=#ffd34c>兩天后</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>조디악 나이츠 본부</color>\\n기사단 회의실 나이츠 홀","JPN":"<color=#ffd34c>ゾディアックナイツ本部</color>\\n騎士団会議室、ナイツホール","ENG":"<color=#ffd34c>Zodiac Knights HQ</color>\\nKnights' meeting room Knights' Hall","TWN":"<color=#ffd34c>十二宮騎士團總部</color>\\n騎士團會議室 騎士大廳"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_A","text":{"KOREA":"말도 안 돼…! 레드시프트 놈들이 무구를 복구해냈다고?","JPN":"そんな馬鹿な……！　レッドシフトのやつらが武具を復元しただと？","ENG":"Impossible...! Are you saying the Red Shift managed to restore the Armament?!","TWN":"這不可能…！紅移那些傢伙居然修復了武具？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_A","text":{"KOREA":"별의 무구에 담긴 인도자의 정수를 그들이 깨우쳤다는 건가?","JPN":"星の武具に込められている導き手の真髄、それを彼らが呼び覚ましたということか？","ENG":"Does that mean they've unlocked the essence of the Star Guide embedded in the Armament?","TWN":"他們領悟了星之武具中蘊含的引導者精髓嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아뇨. 놈들의 무구는 겉모습을 흉내 낸 단순 레플리카에 불과했습니다.","JPN":"いいえ。やつらの武具は外見だけをコピーした、ただのレプリカでしたわ。","ENG":"No. Their so-called Armament was just a cheap replica mimicking the real thing.","TWN":"不，那些傢伙的武具只是模仿外觀的簡單複製品而已。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그들도 그것을 알기에 구원기사단의 고유무장을 사용하려는 것이죠.","JPN":"彼らもそれをわかっているから、救世騎士団の固有武装を利用しようとしているのです。","ENG":"They know it too, which is why they're after the Unique Gear of the Knights of Redemption.","TWN":"他們也知道這一點，所以才想使用救贖騎士團的專屬裝備。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_B","text":{"KOREA":"최악이군. 자칫하면 기사단이 숭앙하는 인도자에 대한 믿음이 뿌리째 뽑힐 거야.","JPN":"最悪だ。下手をすれば騎士団が持っている導き手への信頼が根こそぎ崩れてしまうだろう。","ENG":"This is the worst-case scenario. If this goes poorly, people might lose faith in the Guide we revere.","TWN":"真糟糕。如果不小心的話，騎士團對他們崇敬的引導者的信任可能會被徹底摧毀。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_B","text":{"KOREA":"각국에서 터진 문제를 대처하는 것만으로도 충분히 골치 아프거늘…….","JPN":"各国で発生した問題に対処するだけでも十分困っているというのに……","ENG":"We're already overwhelmed just handling the incidents erupting across the world...","TWN":"光是應對各國爆發的問題就已經夠頭痛的了……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"말씀대로 현재 전세계적인 이상현상이 일어나고 있는 상황입니다.","JPN":"おっしゃるとおり、現在は全世界的に異常現象が発生している状況です。","ENG":"You're right. Strange phenomena are breaking out globally.","TWN":"正如你所說，目前全球範圍內正在發生異常現象。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"관리국의 지원은 기대할 수 없으니, 당장은 저희의 힘으로 그들을 막아야 해요.","JPN":"管理局の支援は期待できませんので、今は私たちの力で彼らを止めなければなりません。","ENG":"With no help coming from the Administration, we'll have to stop them on our own for now.","TWN":"無法指望管理局的支援，所以暫時我們得靠自己的力量阻止他們。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_B","text":{"KOREA":"헛소리. 현 상황에서 무구를 갖춘 이는 자네를 제외하곤 고작 셋이 아닌가?","JPN":"戯言を。今の状況で武具を持っている者は君以外に3人しかいないではないか。","ENG":"Nonsense. Outside of you, only three others have access to an Armament, don't they?","TWN":"胡說八道。現狀下，除了你之外，裝備武具的只有三個人，不是嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_B","text":{"KOREA":"그마저도 피오네 경을 제외하면 전력 미달이야! 멀쩡한 기사들을 사지로 내몰 수는 없네!!","JPN":"それもフィオネ卿を除くと、力不足だ！　まともな騎士たちを死なせるわけにはいかないのだ！！","ENG":"And without Dame Fione, that number barely counts as a force! We can't throw perfectly capable knights into a slaughter!","TWN":"即使是這樣，除了菲奧尼卿之外，戰力也不足！不能把正常的騎士們推向絕境！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_A","text":{"KOREA":"침착하게. 카란티시르가 다른 단원들을 움직이지 않은 데에는 분명 이유가 있어.","JPN":"落ち着きたまえ。カランティシルが他の団員を動かしていないのには、きっと理由があるはずだ。","ENG":"Calm down. There's a reason Carantisir hasn't mobilized the other Red Shift knights yet.","TWN":"冷靜點。卡蘭堤西爾沒有調動其他成員，肯定有原因。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_A","text":{"KOREA":"레드시프트의 전력이 단둘이라면, 승산이 마냥 없지만은 않겠지.","JPN":"レッドシフトの戦力が二人だけなら、勝算がないわけではない。","ENG":"If it's just the two of them, we might still have a chance.","TWN":"如果紅移的戰力只有兩人，那勝算也不是完全沒有吧。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_A","text":{"KOREA":"각 가문에 병력을 차출할 수 있도록 전파하게.","JPN":"各家門に兵力を選び出すよう伝えるのだ。","ENG":"Send word to the houses to mobilize their troops.","TWN":"傳達給各家族，以便徵召兵力。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"ELDER_ZODIAC_NPC_A","text":{"KOREA":"그들이 노리기 전, 우리가 선수를 친다.","JPN":"彼らが狙ってくる前に、私たちが先手を打つ。","ENG":"We strike before they make their move.","TWN":"在他們動手之前，我們先發制人。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_ZODIAC_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"망할 꼰대들. 지들 일 아니라고 아무렇게 말하는 거 봐.","JPN":"くそジジイども。自分たちのことじゃないからって適当に。","ENG":"Damn geezers. Easy for them to talk when it's not their lives on the line.","TWN":"該死的老頑固。看他們隨便說話，因為這不是他們的事。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"레드시프트가 뉘 집 개 이름이야? 잡아 오라면 잡아오게?","JPN":"レッドシフトがそう簡単に倒せるならこっちだって苦労してないわよ。","ENG":"Do they really think I can just catch Red Shift like that?","TWN":"紅移是誰家的狗嗎？說抓就抓？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哀……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"줄리아가 부상을 당한 상황이니, 내가 가세한들 카란티시르를 제압하는 건 어려워.","JPN":"ジュリアは怪我をしてるし、私が加勢してもカランティシルを制圧するのは難しいわ。","ENG":"With Julia wounded, even if I join the fight, taking down Carantisir won't be easy.","TWN":"茱莉亞受了傷，即使我加入也很難制服卡蘭堤西爾。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아셀라라는 녀석은 다른 아이들이 막아낼 수 있겠지만, 문제는 그 아이가 다루는 <color=#ffd34c>부활의 지팡이.</color>","JPN":"アセッラってやつは他の子たちでも止められるはずだけど、問題はあの子が扱ってる<color=#ffd34c>復活の杖</color>。","ENG":"Ascella might be manageable for the others, but the real issue is that <color=#ffd34c>Staff of Resurrection</color> she's wielding.","TWN":"亞瑟拉這個傢伙其他人可以擋住，但問題是她使用的<color=#ffd34c>復活之杖。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그리고… 다른 레드시프트 단원들이 언제든 움직일 수 있다는 점인가.","JPN":"あとは……他のレッドシフト団員たちがいつでも動けるという点かしら。","ENG":"And... the fact that the other Red Shift members could jump in at any time.","TWN":"還有……其他紅移小隊成員隨時可以行動嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ASCELLA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"뭐, 저쪽은 완전 개인주의니 단장이 위기여도 신경 쓰지는 않을 것 같지만…….","JPN":"まあ、あっちは完全に個人主義だし、団長がピンチでも気にしなさそうけど……","ENG":"Not that they'd care if their captain's in danger. Bunch of hardcore individualists over there...","TWN":"嗯，那邊完全是個人主義，就算團長有危機也不會在意吧……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L35_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"어느 쪽이든 귀찮은 건 변함없네, 제길.","JPN":"どっちも面倒なのは一緒ね、くそ。","ENG":"Either way, it's going to be a hassle, shucks.","TWN":"不管是哪一邊，麻煩都是一樣的，真是的。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"별을 추종하는 로웰의 피오네. 부름을 받고 왔습니다.","JPN":"星の追従者、ローウェルのフィオネ。お呼びでしょうか。","ENG":"Fione of House Lowell, follower of the stars. I've come at your request.","TWN":"追隨星星的菲奧尼報到。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"나머지. 이하동문.","JPN":"他。以下同文。","ENG":"The rest of us too.","TWN":"同上。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"리브 언니…….","JPN":"リブさん……","ENG":"Liv...","TWN":"莉芙姊姊……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"불경해요, 리브 경. 원로분들 앞이라고요.","JPN":"不敬です、リブ卿。元老の御前ですよ。","ENG":"Show some respect, Dame Liv. We're standing before the Elders.","TWN":"沒禮貌！莉芙，你面對的可是長老們。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"흥이다. 이전부터 자기들끼리만 이러쿵저러쿵하는데, 내가 뭐 좋아서 예의를 차려?","JPN":"ふんだ。前から自分たちだけでこそこそしてるのに、礼儀正しくする必要ってある？","ENG":"Yeah, yeah. They've been whispering behind closed doors forever, and I'm supposed to bow to that?","TWN":"真有趣。從以前開始他們就自己嘰嘰喳喳的，我幹嘛要客氣呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"원로 할아버지들도 우리 심정을…… ","JPN":"元老のジジイたちもわたしたちの気持ちを……","ENG":"The Elders should try walking in our shoes sometime...","TWN":"元老爺爺們也了解我們的心情……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐야, 한솔이 누님밖에 없네?","JPN":"あれ？　イチロウのとこのお姉さんしかいないじゃない。","ENG":"Wait, is it just Hansol's sister here?","TWN":"什麼啊，只有楊瀚姊姊在嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"여러분? 여긴 어쩐 일로 오신 건가요?","JPN":"皆さん？　ここにはどういったご用ですか？","ENG":"Everyone? What brings you here?","TWN":"你們？怎麼會來這裡？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"평기사분들께 저희를 찾는 사람이 있다는 이야기를 전해 들었습니다.","JPN":"平騎士の方々から、私たちを探している人がいるという話を聞きまして。","ENG":"We heard from the knights that someone was looking for us.","TWN":"有人叫我們來的。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"이상하네요. 회의에서 관련된 내용이 거론된 적은 없었는데.","JPN":"おかしいですわね。会議でそのような内容が出たことはありませんが。","ENG":"Strange. Nothing like that came up in the meeting.","TWN":"真奇怪。在會議上從未提到過相關內容。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"서로 엇갈렸을 수도 있으니, 다른 분들에게 연락해볼까요?","JPN":"入れ違いになったのかもしれませんので、他の方々に連絡してみましょうか？","ENG":"Maybe there was some miscommunication. Should I contact the others?","TWN":"可能是資訊有落差，要不要聯絡其他人試試？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그럴 필요 없네, 메데이아 경.","JPN":"その必要はない、メデイア卿。","ENG":"That won't be necessary, Dame Medea.","TWN":"沒必要，美狄亞。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"저들을 부른 건 나였으니 말이야.","JPN":"彼らを呼んだのは私だ。","ENG":"I was the one who summoned them.","TWN":"是我找他們來的。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"뭐야, 주교 할아버지잖아?","JPN":"なんだ、主教のお爺さんじゃない。","ENG":"Oh, it's Grandpa Bishop.","TWN":"什麼，原來是主教爺爺？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"주교님.\xA0몸이 편찮으신데 그렇게 움직이셔도 괜찮으신가요?","JPN":"主教。お体が不自由なのに動いて大丈夫なんですか？","ENG":"Bishop, are you sure you should be up and about in your condition?","TWN":"主教，你身體不適，這樣行動沒問題嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"몸의 거동이 불편한들 마음의 상처를 입은 자네들만 하겠나.","JPN":"体の不自由さなど、心に傷を負った君たちに比べたらささいなことだ。","ENG":"My body may be frail, but not nearly as much as your wounded hearts.","TWN":"身體行動不便，難道比得上心靈受傷的人嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"본부를 지켜낸 것은 자네들인데 감사 인사 또한 건네지 못했으니…….","JPN":"本部を守ったのは君たちなのに、感謝の言葉も伝えられていない……","ENG":"You defended our HQ. I couldn't even thank you properly...","TWN":"是你們守護了總部，我卻連感謝的話都沒能說出口……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"노약한 병자의 모습이 아닌, 한 명의 기사로서 자네들을 맞이하고 싶었네.","JPN":"老いて弱くなった患者の姿ではなく、一人の騎士として君たちを迎えたかったのだ。","ENG":"So let me face you not as an old invalid, but as a fellow knight.","TWN":"我希望以一名騎士的身份迎接你們，而不是以一個虛弱病人的姿態。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"주교님. 고개를 드십시오!","JPN":"主教、頭をお上げください！","ENG":"Please, Bishop. Raise your head!","TWN":"主教。請抬起頭來！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"맞습니다. 감사 인사라면 저희가 주교실을 찾아가면 되는 문제예요!","JPN":"そうですよ。お礼なら私たちが主教室を訪問すればいいですし！","ENG":"She's right. If it's just gratitude, we could've visited your chambers instead!","TWN":"沒錯。如果是想表達感謝，我們可以去主教室找您就好！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"아니. 내가 해야 할 이야기는 단순 감사 인사만이 아니야.","JPN":"いいや。単に感謝を伝えるだけではないのだ。私が伝えなければならない話は別にある。","ENG":"No. What I have to say is more than simple thanks.","TWN":"不。我想說的不僅僅是感謝的話。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"오늘 그대들을 부른 이유는… 자네들이 알지 못하는 기사단의 이면.","JPN":"今日、君たちを呼んだ理由は……君たちの知らない騎士団の裏面。","ENG":"I called you here today... to tell you the hidden truth behind the Order.","TWN":"今天召集你們的原因是……你們所不知道的騎士團的另一面。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그래. 기사단의 어둠을, 인도자께서 지켜보실 이곳. 나이츠 홀에서 밝히기 위함일세.","JPN":"そう。騎士団の闇を、導き手が見守っているはずのここ、ナイツホールで明かすためなのだ。","ENG":"Yes. I intend to expose the darkness of the Order, here in the Knights' Hall under the gaze of the Guide.","TWN":"是的。為了在騎士團的黑暗中，在引導者注視的這個地方，在騎士大廳中揭示真相。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……잠시만, 길베르트 경!","JPN":"……お待ちください、ギルベルト卿！","ENG":"...Wait, Sir Gilbert!","TWN":"……等一下，吉伯特主教！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"왜 그러지? 싸움을 앞둔 이들에게마저 진실을 감출 셈인가?","JPN":"どうしたのかね？　戦いを控えている者たちにまで真実を隠すつもりなのか？","ENG":"What is it? Do you still intend to keep secrets from those about to go into battle?","TWN":"為什麼這樣？難道連即將戰鬥的人也要隱瞞真相嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"시기가 나쁩니다. 이 아이들이 동료들을 떠나보낸 지 고작 하루예요!","JPN":"時期が良くありません。この子たちは、昨日仲間を失ったばかりなのですよ！","ENG":"It's too soon. They just lost their comrades yesterday!","TWN":"時機不妙。他們才剛剛送別他們的同伴一天！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"원로원의 동의 없이, 이런 돌발 행동은…!!","JPN":"元老院の同意なく、このような突発的な行動は……！！","ENG":"To act without the Elders' approval like this is reckless...!","TWN":"沒有元老院的同意，這種突發行動是……！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"전임 기사단장 시절부터 자네는 늘 말과는 달리 주변을 신경 썼지.","JPN":"前騎士団長の時代から常に君は言葉とはうらはらに、周りを気にしていた。","ENG":"You've always cared more than you let on, even back when you were captain.","TWN":"從擔任騎士團長的時候起，你總是和你的話相反，關心周圍的事情。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그러니 후임들을 보호하고 싶은 마음은 이해하나, 이미 경도 알고 있을 걸세.","JPN":"だから後輩たちを保護しようとするその心は理解するが、すでに卿もわかっているはずだ。","ENG":"I know you want to protect them, but deep down, you already know.","TWN":"所以我理解你想保護後輩的心情，但你應該已經知道了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"이 아이들 또한 긍지 높은 기사단의 일원임을.","JPN":"この子たちもまた、誇り高き騎士団の一員であるということを。","ENG":"These young ones are proud members of the Order.","TWN":"他們也是榮耀的騎士團成員。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그러니 마지막일지도 모르는 이 늙은이의 주책을 이해해주게.","JPN":"どうか、最後かもしれない、この老体のわがままを理解して欲しい。","ENG":"So please, allow this old man one last moment of foolishness.","TWN":"所以請理解這個可能是我這老頭子最後一次的固執。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"아무리 주교님이라도 쉽게 넘어가지 못할 일이에요.","JPN":"いくら主教であっても、ただでは済みませんよ。","ENG":"Even coming from you, Bishop, this isn't something we can just overlook.","TWN":"就算是主教也有您無法輕易解決的事情。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"걱정 말게. 결코 자네들에게 피해 가는 일은 없을 거야.","JPN":"心配せずともよい。君たちに被害が及ぶことは決してないだろう。","ENG":"Don't worry. None of you will be put at risk.","TWN":"別擔心，絕對不會讓你們受到傷害。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만……!!","JPN":"ですが……！！","ENG":"But still...!","TWN":"但是……！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"저기, 부단장. 저게 대체 무슨 소리야?","JPN":"あの、副団長？　あれってどういうことなの？","ENG":"Hey, Deputy. What's going on here?","TWN":"喂，副團長。到底在說什麼？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"기사단의 이면이니 돌발행동이니 당최 모르겠는데.","JPN":"騎士団の裏面とか突発的な行動とか、さっぱりわからないんだけど。","ENG":"What's all this talk about secrets and going rogue? I don't get it.","TWN":"騎士團的內幕還是突發行動，我完全不知道。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……확신할 순 없으나, 한 가지 의심 가는 부분이 있습니다.","JPN":"……確信はできませんが、一つ心当たりはあります。","ENG":"...I'm not completely sure, but there is one thing that's been bothering me.","TWN":"……雖然不能確定，但有一個值得懷疑的地方。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"진짜? 뭔데?","JPN":"本当？　何？","ENG":"Oh? Spill it.","TWN":"真的嗎？什麼事？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"본부가 습격받은 날을 떠올려보세요, 리브 경.","JPN":"本部が襲撃された日のことを思い出してみてください、リブ卿。","ENG":"Think back to the day the HQ was attacked, Dame Liv.","TWN":"回想一下總部被襲擊的那一天，莉芙。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"메데이아 경은 그 날. 레드시프트의 무구가 예전에 훼손되었다고 말하셨습니다.","JPN":"メデイア卿はあの日、レッドシフトの武具は以前に壊れたと言っていました。","ENG":"Dame Medea mentioned that Red Shift's Armament had already been damaged.","TWN":"美狄亞那天說過，紅移的武具曾經被損壞過。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"사라진 무구의 행방은 알려진 적 없으니, 무구가 훼손되었다면 그 이전이란 뜻이겠죠.","JPN":"消えた武具の行方は知らされていませんので、武具が壊れたならその前ということになります。","ENG":"No one ever revealed where it disappeared to, so if it was damaged, it must've been before that.","TWN":"消失的武具去向從未被知曉，如果武具被損壞，那就意味著是在那之前。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"교본에도 나오는 내용이죠. 전임 기사단장이 레드시프트의 무구를 찾아 떠난 뒤 종적을 감췄다고…….","JPN":"教本にもある内容ですね。前騎士団長がレッドシフトの武具を探しに出てからの消息がわからないって……","ENG":"That's what the manuals say. The former captain vanished after going off to retrieve the Armament...","TWN":"這在教科書中也有提到。前任騎士團團長為了尋找紅移的武具而離開後就銷聲匿跡了……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Wait a second.","TWN":"咦？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"무구가 훼손되었다면… 전임 기사단장이 무구를 찾아 나설 이유는 없지 않나요?","JPN":"武具が壊れていたなら……前騎士団長が武具を探しに出る理由はないんじゃないですか？","ENG":"If it was already damaged... Then why did the former captain go searching for it?","TWN":"如果武具被損壞了……前任騎士團長就沒有理由去尋找武具了吧？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"애당초, 블루시프트인 누님이 어떻게 레드시프트의 무구가 훼손된 걸 알고 계신 거죠?","JPN":"そもそも、ブルーシフトのメデイアさんがどうやってレッドシフトの武具が壊れていると知ったんでしょう？","ENG":"And how would you, a Blue Shift, know that a Red Shift's Armament was damaged in the first place?","TWN":"本來，藍移的大姊，你怎麼會知道紅移的武具被損壞了呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"네?","JPN":"え？","ENG":"What?","TWN":"嗯？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"I, uh...","TWN":"那是……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"아무래도 빠져나갈 구멍이 사라진 것 같군.","JPN":"どうやら逃げ場がなくなったようだな。","ENG":"Looks like the cat's out of the bag.","TWN":"看來逃脫的機會已經消失了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"이제 그만 단념하는 게 어떤가, 메데이아 경?","JPN":"もう諦めてはどうかね？　メデイア卿。","ENG":"Why not stop dodging now, Dame Medea?","TWN":"現在放棄怎麼樣，美狄亞？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"왜 원로 회의 직후에 아이들을 불렀나 싶었는데.","JPN":"どうして元老会議の直後にこの子たちを呼び出すのかと思ったら。","ENG":"So that's why you summoned the kids right after the Elders' meeting.","TWN":"為什麼在元老會議結束後立刻召集他們呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"저를 이용하셨군요, 길베르트 경.","JPN":"私を利用したのですね、ギルベルト卿。","ENG":"You used me, didn't you, Sir Gilbert?","TWN":"你利用了我，吉伯特主教。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"허허. 무슨 말인지 모르겠군.","JPN":"はは、何のことだね。","ENG":"Haha. I don't know what you're talking about.","TWN":"呵呵，我不懂你在說什麼。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哈……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"제가 졌어요. 마음대로 하세요.","JPN":"私の負けですわ。ご自由にどうぞ。","ENG":"Fine. I give up. Do as you like.","TWN":"我輸了。隨便你吧。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그래. 무엇부터 이야기해야 좋을까…….","JPN":"さて。何から話せばいいのだろうか……","ENG":"Good. Now, where should I begin...","TWN":"是啊，該從哪裡開始說起呢……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"우선 그대들이 지닌 의문에 해답을 내놓는 것이 좋겠군.","JPN":"まずは君たちの疑問に答えるのが良さそうだ。","ENG":"I suppose answering your questions comes first.","TWN":"首先，我應該為你們心中的疑問提供答案。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"주교님도 레드시프트의 무구에 대해 알고 계신 겁니까?","JPN":"主教もレッドシフトの武具についてご存じなのですか？","ENG":"You knew about Red Shift's Armament, too, Bishop?","TWN":"主教也知道紅移的武具嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"나뿐만이 아닐세. 원로들을 비롯해 기사단의 상부는 대부분 알고 있는 사실이지.","JPN":"私だけではない。元老をはじめ、騎士団の上層部はおおかた知っている事実だ。","ENG":"Not just me. The Elders and most of the upper ranks in the Order are aware.","TWN":"不僅僅是我，包括元老在內的騎士團高層大多都知道這個事實。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그도 그럴 것이, 자네들이 알고 있는 건 과거의 내전을 덮기 위한 구실이니 말이야.","JPN":"なにしろ、君たちが知っている話は過去の内戦を隠すための口実なのだからな。","ENG":"After all, what you know is just the cover story. Something made up to bury the civil war of the past.","TWN":"那也是因為，你們所知道的只是為了掩蓋過去內戰的藉口罷了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"그렇군요. 과거 있었던…….","JPN":"そうですか。過去の……","ENG":"So all of that was just–","TWN":"原來如此。過去發生的……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"내, 내전이라고요?","JPN":"な、内戦？","ENG":"Wait, a civil war?!","TWN":"內、內戰嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……내전이라고 해도 싸운 건 무구를 지닌 열두 명이 고작이었어요.","JPN":"……内戦と言っても、戦ったのは武具を所有していた12人だけでした。","ENG":"...Calling it a civil war might be too generous. Only the twelve wielders of the Armaments fought.","TWN":"……即使是內戰，戰鬥的也不過是擁有武具的十二個人而已。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"카란티시르에 동조한 레드시프트가 열두 무구를 차지하기 위해 일으킨 폭거였죠.","JPN":"カランティシルに同調したレッドシフトが12武具を手に入れるために起こした暴挙でしたわ。","ENG":"Red Shift, led by Carantisir, rose up in an attempt to seize all twelve.","TWN":"這是與卡蘭堤西爾同調的紅移為了奪取十二聖遺物而引發的暴行。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"열두 무구를 차지하겠다는 이유로 동료에게 창칼을 겨눴다는 겁니까?","JPN":"12武具を手に入れるという理由だけで、仲間に武器を向けたということですか？","ENG":"They turned their weapons on their comrades just to claim the Armaments?","TWN":"為了奪取十二聖遺物，竟然對同伴揮刀相向嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"레드시프트의 단장인 카란티시르는 누구보다도 힘을 갈망하는 사내였다.","JPN":"レッドシフトの団長であるカランティシルは、誰よりも力を欲する男であった。","ENG":"Carantisir, Red Shift's leader, was a man who craved power above all.","TWN":"紅移的團長卡蘭堤西爾是一個比任何人都渴望力量的男人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그는 각기의 가문이 무구를 소유한 현 체제에 불만을 품고, 또한 의문을 제기했지.","JPN":"彼は各々の家門が武具を所有する現在の体制に不満を感じ、疑問を呈したのだ。","ENG":"He despised the current system, where each family held one Armament, and questioned it.","TWN":"他對各家族擁有武具的現行制度感到不滿，並提出了質疑。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"열두 별의 무구는 오롯이 한 명을 위해 존재해야 한다며 말이야.","JPN":"12の星の武具はただ一人のために存在するべきだとな。","ENG":"He believed all twelve Star Armaments should belong to a single wielder.","TWN":"十二星的聖遺物必須只為一個人而存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_04","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CARANTISIR_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 별의 무구는 그 안에 담긴 별빛을 다룰 수 있는 적합자만이 사용 가능합니다.","JPN":"でも、星の武具はその中に込められている星の光を扱える適合者だけが使えるものですよ。","ENG":"But the Armaments can only be used by those compatible with the starlight they carry.","TWN":"但是，星之武具只有能夠駕馭其中星光的適合者才能使用。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"가문 간의 관계를 차치하더라도, 복수의 무구를 다룬 기사의 전례는 이제껏 없었어요.","JPN":"家門同士の関係はさておくとしても、複数の武具を扱った騎士の前例は今までありません。","ENG":"Even setting aside family politics, there's never been a case where someone could wield more than one.","TWN":"即使撇開家族之間的關係不談，至今也沒有處理多種武具的騎士的先例。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"맞아요. 저도 리브 언니의 리브라 스케일은 무거워서 못 드는 걸요.","JPN":"そうですよ。私はリブさんのリブラ・スケールは重くて持てないんです。","ENG":"Right! I can't even lift Liv's Libra Scale because it's too heavy.","TWN":"沒錯。我也舉不起莉芙姊姊的天秤，因為太重了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그가 무엇을 알아냈는지는 알 수 없네.","JPN":"彼が何を見つけてしまったのかは知る由もないが。","ENG":"No one knows what he discovered.","TWN":"我不知道他發現了什麼。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"하지만 확실한 건, 그가 알아낸 무언가는 레드시프트를 움직이기에 충분했고.","JPN":"確かなのは、彼が見つけた何かはレッドシフトを行動に移させるに足る理由であり。","ENG":"But whatever it was, it was enough to rally Red Shift.","TWN":"但可以確定的是，他發現的某些東西足以讓紅移行動。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"그걸 막는 과정에서 전임 기사단장의 종적이 묘연해졌지.","JPN":"それを止める過程で前騎士団長が行方不明となったのだ。","ENG":"And during the battle to stop him, the former captain vanished.","TWN":"在阻止這件事的過程中，前任騎士團團長變得下落不明。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어라… 뭔가 이상한데?","JPN":"あれ……なんかおかしいよ。","ENG":"Wait a sec... Something doesn't add up.","TWN":"欸……有點不對勁……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"전임 기사단장은 기사단에서 거의 변절자 취급이잖아.","JPN":"前騎士団長は、騎士団ではほぼ裏切り者扱いしてない？","ENG":"Everyone in the Order treats the former captain like a traitor.","TWN":"前任騎士團長在騎士團幾乎被視為叛徒。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"이렇게만 들으면 그냥 좋은 사람 아니야?","JPN":"今聞いてるかぎりだと、ただのいい人って感じなんだけど。","ENG":"But from the sound of this, wasn't he just trying to do the right thing?","TWN":"這樣聽起來不就是個好人嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……기사단의 존속을 위해.","JPN":"……騎士団の存続のために。","ENG":"...So you twisted the truth...","TWN":"……為了騎士團的存亡。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"진실을 왜곡시킨 겁니까?","JPN":"真実を歪曲したのですか？","ENG":"To preserve the Order?","TWN":"你是在歪曲事實嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"구차한 변명에 불과하나, 당시에는 그게 최선이라 생각했네.","JPN":"つまらない言い訳だが、その当時はそれが最善だと思った。","ENG":"A pitiful excuse, I know. But at the time, we thought it was the only way.","TWN":"不過是無力的辯解罷了，當時我以為那是最好的選擇。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"무구의 선택을 받은 이들이 서로 목숨을 걸고 싸웠다는 사실이 밝혀지면.","JPN":"武具に選ばれた者たちが互いの命を奪うような闘いをした、という事実が明らかになれば。","ENG":"If the public found out that the chosen wielders of the Armaments fought each other to the death...","TWN":"要是被武具選中的人彼此打個你死我活的事情被外界知道，"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"별의 무구. 더 나아가 기사단의 존속이 위태로워질 테니 말이야.","JPN":"星の武具、さらには騎士団の存続が危うくなるはずだからだ。","ENG":"The Star Armaments and the Order itself might not have survived.","TWN":"不只是星之武具，甚至連騎士團的存續都會岌岌可危。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"그, 그런…….","JPN":"そ、そんな……","ENG":"Th-that's...","TWN":"那，那……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"그럼 단장님은…….","JPN":"じゃあ、団長は……","ENG":"Then Captain is...","TWN":"團長……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"우, 웃기지 마! 그것 때문에 단장이 얼마나 힘들어했는데?","JPN":"ふ、ふざけないでよ！　そのせいで団長どれだけ辛かったと思ってるの？","ENG":"D-don't be absurd! Do you have any idea how much Captain suffered because of all this?!","TWN":"別，別開玩笑了！團長為了那件事有多辛苦，你知道嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_04"},{"id":"L3_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"적어도 단장한테는 말해줄 수 있었던 거 아니야?","JPN":"せめて団長にだけは話してあげても良かったんじゃないの？","ENG":"You could've at least told her the truth!","TWN":"至少應該告訴團長吧？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"진실을 묻는데 동의한 건 전임 기사단장 역시 마찬가지예요.","JPN":"真実を隠すことについては前騎士団長も同意していました。","ENG":"The former captain agreed to hide it too.","TWN":"前任騎士團長也同意追問真相。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"당연히, 그 대상에는 에스테로사 경도 포함되어 있었고요.","JPN":"当然、その対象にはエステロサ卿も含まれています。","ENG":"And yes, that included Dame Esterosa.","TWN":"當然，那個對象也包括艾斯特洛索。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"……뭐야, 그게.","JPN":"何よ、それ。","ENG":"What?","TWN":"……搞什麼。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L8_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"아까부터 뭐냐고! 그런 일이 있었다고 말하면 알았다고 납득할 줄만 알았어?","JPN":"さっきから何なのよ！　そんなことがあったって言えば、ああ、そうですかって納得するとでも思った？","ENG":"What's that supposed to mean?! Did you think we'd just accept this?","TWN":"從剛才開始就在胡說八道！你以為你這樣隨便說說，我就會默默接受嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"적어도 우리한테는 말해줄 수 있었잖아! 그러면, 그러면…!","JPN":"少なくとも私たちには話しても良かったじゃない！　そうしたら、そうしたら……！","ENG":"You could've told us! Then... then...!","TWN":"至少可以告訴我們吧！那樣的話，那樣的話……！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"단장이 떠나지도, 아저씨들도 그렇게 허무하게 죽지도 않았을 거라고!","JPN":"団長がここを出ることも、おじさんたちがあんな虚しく死ぬこともなかったよ！","ENG":"Captain wouldn't have left. And those men wouldn't have died in vain!","TWN":"至少團長不會離開，叔叔們也不會就這樣毫無意義地死去！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"변명은 하지 않겠네. 그 모든 건 우리가 속죄해야 할 죄악임이 분명하니.","JPN":"言い訳はしない。そのすべては私たちが償うべき罪であることに違いはないのだから。","ENG":"I won't make excuses. This is a sin we must all atone for.","TWN":"我不會找藉口。這一切顯然是我們必須贖罪的罪惡。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"하지만… 염치 불고하고 지금은 자네들에게 부탁할 수밖에 없군.","JPN":"だが……それでも今は君たちに頼るしかないのだ。","ENG":"But... shameless as it may be, I came to ask for your help now.","TWN":"但是……現在只能厚著臉皮拜託你們了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"기사단이 과거와 같은 전철을 밟지 않기 위해…….","JPN":"騎士団が過去と同じことを繰り返さないためには……","ENG":"To keep the Order from repeating its past mistakes...","TWN":"為了不讓騎士團重蹈覆轍……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"카란티시르를 막기 위해, 자네들의 힘이 필요해.","JPN":"カランティシルを止めるためには、君たちの力が必要だ。","ENG":"We need your strength to stop Carantisir.","TWN":"為了阻止卡蘭堤西爾，我們需要你的力量。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……리브 경.","JPN":"……リブ卿。","ENG":"...Dame Liv.","TWN":"……莉芙。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"나도 알아. 엉뚱한데 화풀이하면 안 된다는 거.","JPN":"わかってるよ。八つ当たりしたって意味ないことくらい。","ENG":"I know. I shouldn't be lashing out like this.","TWN":"我也知道。不能隨便遷怒於別人。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"지금이… 그럴 때가 아니라는 것도.","JPN":"今は……そんな場合じゃないってことも。","ENG":"And that... this isn't the time for it.","TWN":"現在不是那樣的時候。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그래도 전부 납득한 건 아니야.","JPN":"でも全部納得したわけじゃない。","ENG":"But that doesn't mean I'm okay with any of it.","TWN":"不過我並沒有完全接受。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"당장은 아저씨들의 복수를 하는 게 우선이니까!","JPN":"今はおじさんたちの復讐が先だから！","ENG":"Right now, I just want revenge for those old guys we lost!","TWN":"現在最重要的是為叔叔們復仇！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"예. 그들이 강함을 곧 정의로 여긴다면, 저희의 정의를 창칼로 증명하면 그만입니다.","JPN":"はい。彼らが力を正義だと思ってるなら、私たちの正義を武器をもって証明すればいいだけの話です。","ENG":"Yes. If they think strength is justice, then we'll prove our justice with blade and spear.","TWN":"是的。如果他們認為強大就是正義，那麼我們就用刀槍來證明我們的正義即可。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"저도 마음 같아서는 여러분들과 함께 싸우고 싶지만… 발목을 잡고 싶지도 않아요.","JPN":"私も気持ちはみんなと一緒に戦いたいんですけど……足手まといになりたくもないです。","ENG":"I wish I could fight with you... But I don't want to hold you back.","TWN":"我也很想和大家並肩作戰，但我不想拖累你們。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 아프면 언제든 불러 주세요! 제가 열심히 치료할게요!!","JPN":"だから怪我をしたらいつでも呼んでください！　私が頑張って治療しますから！！","ENG":"So if anyone gets hurt, just call for me! I'll do my best to heal you!!","TWN":"所以如果有人受傷的話，請隨時叫我！我會努力治療大家的！！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L38_1","type":"dialog","speaker":"CLERIC_NPC_NULL_NULL","text":{"KOREA":"메데이아 경. 부탁하네.","JPN":"メデイア卿。頼んだぞ。","ENG":"Dame Medea. I leave the rest to you.","TWN":"美狄亞。拜託了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"……네. 알겠습니다.","JPN":"……はい。かしこまりました。","ENG":"...Understood.","TWN":"……是。我知道了。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"얼마 전 관리국으로부터 구원기사단의 무구를 인수받았습니다.","JPN":"少し前に管理局から救世騎士団の武具を受け取りました。","ENG":"Not long ago, we received the Armaments of the Knights of Redemption from the Administration.","TWN":"不久前，我從管理局接收了救贖騎士團的武具。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"원로원은 놈들의 목적이 이러한 고유무장이라는 것에서 방안을 착안.","JPN":"元老院はやつらの目的がこの固有武装であることに着目しました。","ENG":"The Elder Council took note that Red Shift's target was these Unique Gear.","TWN":"他們的目標是這種專屬武裝，元老院根據這一點上制定出方案。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"레드시프트가 공격할 수밖에 없는 환경을 만들고, 그곳에 주요 병력을 배치시킬 겁니다.","JPN":"レッドシフトが攻撃するしかない環境を作り、そこに主要兵力を配置させます。","ENG":"So their plan is to place those Armaments somewhere Red Shift won't be able to resist attacking and station elite forces there.","TWN":"我們將創造一個紅移不得不攻擊的環境，並在那裡部署主要兵力。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"작전의 시작은……","JPN":"作戦開始は……","ENG":"The commencement of this operation will be–","TWN":"作戰的開始是……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"꾸물거릴 틈이 어딨어? 당장 출발하자고!","JPN":"ぐずぐずしてる暇なんてない。すぐに出発しよう！","ENG":"What are we waiting for?! Let's move out right now!","TWN":"哪有時間磨蹭？趕緊出發吧！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"의욕이 앞서는 건 좋은데, 위치는 아직 안 알려드렸는데요.","JPN":"やる気があるのはいいのですが、まだ位置を言っていませんわ。","ENG":"I like the enthusiasm, but I haven't even told you where we're going yet.","TWN":"有幹勁是好事，但我還沒告訴你位置呢。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"휴우… 한솔 경. 죄송하지만 리브 경을 부탁드릴 수 있을까요?","JPN":"ふう……ヤガミ卿。申し訳ありませんが、リブ卿をお願いできますか？","ENG":"Phew... Sir Hansol, would you mind keeping an eye on Dame Liv?","TWN":"呼……楊瀚卿。抱歉，可以拜託你照顧一下莉芙嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"하, 한솔 <color=#ffd34c>경</color>이요?","JPN":"や、ヤガミ<color=#ffd34c>卿</color>ですか？","ENG":"S-<color=#ffd34c>Sir</color> Hansol...?","TWN":"你，你叫我楊瀚<color=#ffd34c>卿</color>嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"왜요?","JPN":"何でしょう？","ENG":"What?","TWN":"怎麼了嗎？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"아무것도 아닙니다! 분부대로 움직이겠습니다!","JPN":"何でもありません！　ご指示に従います！","ENG":"Nothing! I'll do as you say!","TWN":"沒什麼！我會按指示行動的！"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"메데이아 경에게는 매번 도움을 받는군요.","JPN":"メデイア卿にはいつも助けてもらってばかりですね。","ENG":"You always come through for us, Dame Medea.","TWN":"每次都得到美狄亞的幫助呢。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"레드시프트의 일이 있다지만, 관리국으로부터 고유무장을 받아 내실 줄은 몰랐습니다.","JPN":"レッドシフトのことがあるとはいえ、管理局が固有武装を出してくれるとは思いませんでした。","ENG":"I never expected the Administration to hand over the Unique Gear...","TWN":"雖然有紅移的任務，但沒想到能從管理局獲得專屬武裝。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"에이~. 제가 무슨 능력이 있다고 그걸 받아내겠어요?","JPN":"もう～、私に固有武装をくれるわけないじゃないですか。","ENG":"Oh, please. What power do I have to pull that off?","TWN":"哎～我有什麼能力能接受那個呢？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"감사 인사를 건넬 사람은 따로 있어요, 피오네 경.","JPN":"お礼をすべき人は他にいるのですよ、フィオネ卿。","ENG":"There's someone else you should be thanking, Dame Fione.","TWN":"要感謝的人另有其人，菲奧尼。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"네?","JPN":"え？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"후후. 아무것도 아니에요.","JPN":"ふふ、何でもありません。","ENG":"Haha. Never mind.","TWN":"呵呵，沒什麼。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"LAUGH2"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MEDEA_ZODIAC_NULL_NULL","text":{"KOREA":"그럼, 저희도 슬슬 움직여 볼까요?","JPN":"では、そろそろ私たちも始めましょうか。","ENG":"Now then, shall we get moving too?","TWN":"那我們也該開始行動了吧？"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_LOGIN2","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEDEA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};